cat > .pi-eval-sample-blackbox.zig <<'EOF'
const std = @import("std");
const app = @import("src/main.zig");

const kind_count = @typeInfo(app.SampleKind).@"enum".fields.len;

test "black-box sample analysis semantics" {
    const thresholds = [_]app.Threshold{
        .{ .kind = .temperature, .min_quality = 6, .limit = 25, .required_flags = 0b0001 },
        .{ .kind = .pressure, .min_quality = 4, .limit = 1008, .required_flags = 0 },
        .{ .kind = .vibration, .min_quality = 5, .limit = 10, .required_flags = 0b0010 },
    };
    const samples = [_]app.Sample{
        .{ .sensor_id = 1, .kind = .temperature, .tick = 10, .value = 24, .quality = 8, .flags = 0b0001 },
        .{ .sensor_id = 2, .kind = .temperature, .tick = 11, .value = 27, .quality = 8, .flags = 0b0001 },
        .{ .sensor_id = 3, .kind = .temperature, .tick = 12, .value = 30, .quality = 3, .flags = 0b0001 },
        .{ .sensor_id = 4, .kind = .pressure, .tick = 13, .value = 1009, .quality = 5, .flags = 0 },
        .{ .sensor_id = 5, .kind = .vibration, .tick = 14, .value = 11, .quality = 6, .flags = 0b0010 },
        .{ .sensor_id = 6, .kind = .voltage, .tick = 15, .value = 220, .quality = 9, .flags = 0 },
    };
    var stats: [kind_count]app.KindStats = undefined;
    var alerts: [samples.len]app.Alert = undefined;
    const result = try app.analyzeSamplesInto(thresholds[0..], samples[0..], stats[0..], alerts[0..]);
    try std.testing.expectEqual(@as(usize, 4), result.accepted);
    try std.testing.expectEqual(@as(usize, 2), result.rejected);
    try std.testing.expectEqual(@as(usize, 3), result.alert_count);
    try std.testing.expectEqual(@as(usize, 2), stats[@intFromEnum(app.SampleKind.temperature)].count);
    try std.testing.expectEqual(@as(i64, 51), stats[@intFromEnum(app.SampleKind.temperature)].total);
    try std.testing.expectEqual(@as(i32, 24), stats[@intFromEnum(app.SampleKind.temperature)].min);
    try std.testing.expectEqual(@as(i32, 27), stats[@intFromEnum(app.SampleKind.temperature)].max);
    try std.testing.expectEqual(@as(usize, 1), stats[@intFromEnum(app.SampleKind.temperature)].alert_count);
    try std.testing.expectEqual(@as(u16, 2), alerts[0].sensor_id);
    try std.testing.expectEqual(app.SampleKind.temperature, alerts[0].kind);
    try std.testing.expectEqual(@as(u16, 4), alerts[1].sensor_id);
    try std.testing.expectEqual(app.SampleKind.pressure, alerts[1].kind);
    try std.testing.expectEqual(@as(u16, 5), alerts[2].sensor_id);
    try std.testing.expectEqual(app.SampleKind.vibration, alerts[2].kind);
}

test "black-box output sizes" {
    const thresholds = [_]app.Threshold{
        .{ .kind = .temperature, .min_quality = 0, .limit = 0, .required_flags = 0 },
    };
    const samples = [_]app.Sample{
        .{ .sensor_id = 1, .kind = .temperature, .tick = 1, .value = 1, .quality = 1, .flags = 0 },
        .{ .sensor_id = 2, .kind = .temperature, .tick = 2, .value = 2, .quality = 1, .flags = 0 },
    };
    var short_stats: [kind_count - 1]app.KindStats = undefined;
    var alerts: [samples.len]app.Alert = undefined;
    try std.testing.expectError(error.OutputTooSmall, app.analyzeSamplesInto(thresholds[0..], samples[0..], short_stats[0..], alerts[0..]));
    var stats: [kind_count]app.KindStats = undefined;
    var short_alerts: [1]app.Alert = undefined;
    try std.testing.expectError(error.OutputTooSmall, app.analyzeSamplesInto(thresholds[0..], samples[0..], stats[0..], short_alerts[0..]));
}
EOF
zig test .pi-eval-sample-blackbox.zig -OReleaseFast
